// ফুলস্ক্রিন টগল করার মেইন ফাংশন
    window.toggleS2Theater = async function() {
      const elem = document.getElementById('s2_player_area');

      // যদি বর্তমানে ফুলস্ক্রিন না থাকে, তবে ফুলস্ক্রিন করো
      if (!document.fullscreenElement && !document.webkitFullscreenElement) {
        try {
          if (elem.requestFullscreen) {
            await elem.requestFullscreen();
          } else if (elem.webkitRequestFullscreen) {
            await elem.webkitRequestFullscreen();
          }

          // মোবাইল ল্যান্ডস্কেপ মোড (আড়াআড়ি)
          if (screen.orientation && screen.orientation.lock) {
            await screen.orientation.lock('landscape').catch(() => {});
          }
        } catch (err) {
          console.log(err);
        }
      } else {
        // যদি অলরেডি ফুলস্ক্রিন থাকে, তবে এক্সিট করো
        exitS2FullScreen();
      }
    };

    // ফুলস্ক্রিন থেকে বের হওয়ার ফাংশন
    window.exitS2FullScreen = function() {
      if (document.exitFullscreen) {
        document.exitFullscreen();
      } else if (document.webkitExitFullscreen) {
        document.webkitExitFullscreen();
      }

      if (screen.orientation && screen.orientation.unlock) {
        screen.orientation.unlock();
      }
    };

    // স্মার্ট ক্লিক লজিক: ভিডিও এরিয়াতে ক্লিক করলে ফুলস্ক্রিন টগল হবে
    // কিন্তু বাটনগুলোতে ক্লিক করলে যেন ফুলস্ক্রিন বন্ধ না হয়
    document.getElementById('s2_player_area').addEventListener('click', function(e) {
      // যদি ক্লিকটি বাটন (Button), লিঙ্ক (A) বা সার্ভার লিস্টের ওপর না হয়
      if (e.target.tagName !== 'BUTTON' && e.target.tagName !== 'A' && !e.target.closest('.s2-server-row')) {
        // শুধুমাত্র ফুলস্ক্রিন মুডে থাকা অবস্থায় এই ক্লিক কাজ করবে (স্মার্ট এক্সিট)
        if (document.fullscreenElement || document.webkitFullscreenElement) {
            toggleS2Theater();
        }
      }
    });
    function getMatchDuration(category) { return category === "Cricket" ? 10 * 3600000 : 4 * 3600000; }

    window.startS2Streaming = function() {
      const p = document.getElementById('s2_iframe_player'); const ph = document.getElementById('s2_video_placeholder');
      if(currentS2Url) { p.src = currentS2Url; p.style.display = "block"; ph.style.display = "none"; }
    };

    window.filterS2Category = function(cat, element) {
      activeCat = cat; activeStatus = "All"; 
      document.querySelectorAll('.s2-filter-item').forEach(el => el.classList.remove('active'));
      element.classList.add('active');
      renderMatchList();
    };

    window.filterS2Status = function(status, element) {
      activeStatus = status; activeCat = "All"; 
      document.querySelectorAll('.s2-st-btn').forEach(el => el.classList.remove('active'));
      element.classList.add('active');
      renderMatchList();
    };

    function formatDate(d) {
      const months = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
      const days = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];
      return `${days[d.getDay()]}, ${months[d.getMonth()]} ${d.getDate()}`;
    }

    function renderMatchList() {
      const listDiv = document.getElementById('s2_match_list_container'); listDiv.innerHTML = '';
      const now = new Date().getTime();

      // COUNTING LOGIC (RESTORED)
      let totalLive = 0, totalUpcoming = 0, totalEnded = 0;
      liveMatches.forEach(m => {
        const k = new Date(m.kickoffTime).getTime();
        const dur = getMatchDuration(m.category);
        if(now >= k && now <= (k + dur)) totalLive++;
        else if (now < k) totalUpcoming++;
        else if (now > (k + dur)) totalEnded++;
      });
      document.getElementById('s2_live_btn').innerText = `LIVE (${totalLive})`;
      document.getElementById('s2_upcoming_btn').innerText = `UPCOMING (${totalUpcoming})`;
      document.getElementById('s2_ended_btn').innerText = `ENDED (${totalEnded})`;

      let filtered = liveMatches.filter(match => {
        const k = new Date(match.kickoffTime).getTime();
        const dur = getMatchDuration(match.category);
        const isLive = now >= k && now <= (k + dur);
        const isUpcoming = now < k;
        const isEnded = now > (k + dur);
        if (activeCat !== "All") return match.category === activeCat;
        if (activeStatus !== "All") {
          if (activeStatus === "Live") return isLive;
          if (activeStatus === "Upcoming") return isUpcoming;
          if (activeStatus === "Ended") return isEnded;
        }
        return true;
      });

      filtered.sort((a, b) => {
        const aK = new Date(a.kickoffTime).getTime();
        const bK = new Date(b.kickoffTime).getTime();
        const aDur = getMatchDuration(a.category);
        const bDur = getMatchDuration(b.category);
        let pA = (now >= aK && now <= (aK + aDur)) ? 0 : (now < aK ? 1 : 2);
        let pB = (now >= bK && now <= (bK + bDur)) ? 0 : (now < bK ? 1 : 2);
        if (pA !== pB) return pA - pB;
        return aK - bK; 
      });

      filtered.forEach(match => {
        const idx = liveMatches.indexOf(match); const k = new Date(match.kickoffTime);
        const hrs = k.getHours() % 12 || 12; const mins = k.getMinutes().toString().padStart(2, '0');
        const card = document.createElement('div'); card.className = 's2-match-card' + (idx === currentActiveMatchIdx ? ' active' : '');
        card.innerHTML = `
${match.league}



--${formatDate(k)}



${match.team1}

VS

${match.team2}


${hrs}:${mins} ${k.getHours() >= 12 ? 'PM' : 'AM'}
          `;
        card.onclick = () => playS2Match(match, card, false, idx);
        listDiv.appendChild(card);
      });
      updateTimers();
    }

    function playS2Match(ch, element, isAuto = false, idx = 0) {
      currentActiveMatchIdx = idx;
      const k = new Date(ch.kickoffTime);
      document.getElementById('s2_current_match_title').innerHTML = `${ch.team1}VS${ch.team2}`;
      const hrs = k.getHours() % 12 || 12; const mins = k.getMinutes().toString().padStart(2, '0');
      document.getElementById('s2_ph_kickoff_static').innerText = `${formatDate(k)} | ${hrs}:${mins} ${k.getHours() >= 12 ? 'PM' : 'AM'}`;
      document.getElementById('s2_ph_flag1').src = ch.logo1; document.getElementById('s2_ph_flag1').style.display = 'block';
      document.getElementById('s2_ph_flag2').src = ch.logo2; document.getElementById('s2_ph_flag2').style.display = 'block';
      document.querySelectorAll('.s2-match-card').forEach(el => el.classList.remove('active'));
      if(element) element.classList.add('active');
      const p = document.getElementById('s2_iframe_player'); const ph = document.getElementById('s2_video_placeholder');
      p.src = "about:blank"; p.style.display = "none"; ph.style.display = "flex";
      document.getElementById('s2_placeholder_teams').innerText = `${ch.team1} VS ${ch.team2}`;
      currentS2Url = ch.urls[0];
      const srvBox = document.getElementById('s2_servers_container'); srvBox.innerHTML = '';
      ch.urls.forEach((url, i) => {
        const btn = document.createElement('button'); btn.className = 's2-srv-btn' + (i === 0 ? ' active' : '');
        btn.innerText = `SERVER ${i+1}`; btn.onclick = () => {
          document.querySelectorAll('.s2-srv-btn').forEach(b => b.classList.remove('active'));
          btn.classList.add('active'); currentS2Url = url; startS2Streaming();
        }; srvBox.appendChild(btn);
      });
      if(ch.tabButtons) {
        ch.tabButtons.forEach(tab => {
          const btn = document.createElement('button'); btn.className = 's2-srv-btn s2-tab-btn';
          btn.innerText = tab.name; btn.onclick = () => window.open(tab.link, '_blank');
          srvBox.appendChild(btn);
        });
      }
      if(!isAuto) document.getElementById('s2_player_area').scrollIntoView({ behavior: 'smooth' });
    }

function updateTimers() {
      const now = new Date().getTime();
      liveMatches.forEach((match, idx) => {
        const k = new Date(match.kickoffTime).getTime(); 
        const diff = k - now; 
        const dur = getMatchDuration(match.category);
        const el = document.getElementById(`s2-timer-${idx}`);
        const phCountdown = document.getElementById('s2_ph_countdown');

        let displayStr = "";

        if(now > (k + dur)) {
          // খেলা শেষ হয়ে গেলে
          displayStr = "ENDED";
          if(idx === currentActiveMatchIdx && phCountdown) {
            phCountdown.innerText = "Match Ended";
          }
        }
        else if(diff <= 0) {
          // খেলা যখন লাইভ (Live Now)
          displayStr = ` LIVE NOW`;
          if(idx === currentActiveMatchIdx && phCountdown) {
            phCountdown.innerText = "Match Started - Watch Now!";
            phCountdown.style.color = "#ef4444"; // লাইভ হলে লাল রঙ দেখাবে
          }
        }
        else {
          // খেলা শুরু হতে দেরি থাকলে (Countdown)
          const d = Math.floor(diff / 86400000); 
          const h = Math.floor((diff % 86400000) / 3600000);
          const m = Math.floor((diff % 3600000) / 60000); 
          const s = Math.floor((diff % 60000) / 1000);

          displayStr = d > 0 ? `${d}d ${h}h ${m}m` : `${h}h ${m}m`;

          if(idx === currentActiveMatchIdx && phCountdown) {
            phCountdown.innerText = `Starts in: ${d > 0 ? d+'d ' : ''}${h}h ${m}m ${s}s`;
            phCountdown.style.color = "var(--s2-timer-text)"; // সাধারণ রঙ
          }
        }

        if(el) el.innerHTML = displayStr;
      });
    }

    // এটি যেকোনো ফুলস্ক্রিন ইভেন্ট ডিটেক্ট করবে (ভিডিওর ভেতর বা বাইরে)
    document.addEventListener('fullscreenchange', handleS2Orientation);
    document.addEventListener('webkitfullscreenchange', handleS2Orientation);

    async function handleS2Orientation() {
      // যদি পেজে কোনো কিছু ফুলস্ক্রিন অবস্থায় থাকে
      if (document.fullscreenElement || document.webkitFullscreenElement) {
        try {
          // মোবাইল ল্যান্ডস্কেপ মোড লক করার চেষ্টা
          if (screen.orientation && screen.orientation.lock) {
            await screen.orientation.lock('landscape').catch(function(error) {
              console.log("Orientation lock ignore: ", error);
            });
          }
        } catch (err) {
          console.log("Orientation error: ", err);
        }
      } else {
        // ফুলস্ক্রিন থেকে বের হয়ে গেলে রোটেশন আনলক করে দিবে
        if (screen.orientation && screen.orientation.unlock) {
          screen.orientation.unlock();
        }
      }
    }
    function initS2Filter() {
      const fb = document.getElementById('s2_category_filter');
      const cats = []; liveMatches.forEach(m => { if(!cats.find(c => c.name === m.category)) cats.push({name: m.category, icon: m.categoryIcon}); });
      cats.forEach(cat => {
        const item = document.createElement('div'); item.className = 's2-filter-item';
        item.onclick = function() { filterS2Category(cat.name, this); };
        item.innerHTML = `${cat.name}`;
        fb.appendChild(item);
      });
    }
    document.addEventListener('DOMContentLoaded', () => { initS2Filter(); renderMatchList(); setInterval(updateTimers, 1000); });
  })();

