      function playS3Channel(ch, element) {
        const player = document.getElementById('s3_iframe_player');
        document.getElementById('s3_title_text').innerText = ch.name;
        document.querySelectorAll('.s3-chan-item').forEach(el => el.classList.remove('active'));
        if(element) element.classList.add('active');

        const srvBox = document.getElementById('s3_servers_container');
        srvBox.innerHTML = '';

        ch.urls.forEach((url, i) => {
          const btn = document.createElement('button');
          btn.className = 's3-srv-btn' + (i === 0 ? ' active' : '');
          btn.innerHTML = ` Server ${i+1}`;
          btn.onclick = function() {
            document.querySelectorAll('.s3-srv-btn').forEach(b => b.classList.remove('active'));
            btn.classList.add('active');
            player.src = url;
          };
          srvBox.appendChild(btn);
          if(i === 0) {
            player.src = url;
          }
        });

        // চ্যানেলে ক্লিক করলে প্লেয়ারের কাছে নিয়ে যাবে
        document.getElementById('s3_player_top').scrollIntoView({ behavior: 'smooth' });
      }

      function initS3() {
        const listDiv = document.getElementById('s3_channels_list_container');
        if(!listDiv) return;
        listDiv.innerHTML = '';
        myChannels.forEach((ch, idx) => {
          const div = document.createElement('div');
          div.className = 's3-chan-item';
          div.innerHTML = `

📺


              ${ch.name}
              Online • 1080p

          `;
          div.onclick = function() { playS3Channel(ch, div); };
          listDiv.appendChild(div);
          if(idx === 0) playS3Channel(ch, div);
        });
      }

      document.addEventListener('DOMContentLoaded', initS3);
    })();

body.script:
// Script for #laliga tab's internal tabbing system
const laligaContainer = document.getElementById('laliga'); // Get the parent container
if (laligaContainer) {
    const tabs_laliga = laligaContainer.querySelectorAll('#verticalTabsMenu button');
    const contents_laliga = laligaContainer.querySelectorAll('#verticalTabsContent > .tabContent'); // Direct children
    const searchInput_laliga = laligaContainer.querySelector('#tabSearchInput');

    function activateTab_laliga(tab) {
      tabs_laliga.forEach(t => t.classList.remove('active'));
      contents_laliga.forEach(c => c.classList.remove('active'));

      tab.classList.add('active');
      const targetId = tab.getAttribute('data-tab');
      const targetContent = laligaContainer.querySelector(`#${targetId}`); // Query within laligaContainer
      if (targetContent) {
          targetContent.classList.add('active');

          const iframeInTarget = targetContent.querySelector('iframe');
          if (iframeInTarget && iframeInTarget.dataset.originalSrc) { 
              // This is generally handled by the main openTab's iframe logic when switching main tabs.
              // If this internal tab was just hidden/shown without main tab change, this might be needed.
              // However, the problem focuses on main tab switching.
          }
      }
    }

    tabs_laliga.forEach(tab => {
      tab.addEventListener('click', () => activateTab_laliga(tab));
    });

    if (searchInput_laliga) {
      searchInput_laliga.addEventListener('input', () => {
        const query = searchInput_laliga.value.toLowerCase();
        let firstMatch = null;

        tabs_laliga.forEach(tab => {
          const text = tab.textContent.toLowerCase();
          const match = text.includes(query);
          tab.style.display = match || query === "" ? "block" : "none";
          if (match && !firstMatch) firstMatch = tab;
        });

        if (firstMatch) {
          if (!firstMatch.classList.contains('active')) {
               activateTab_laliga(firstMatch);
          }
        } else if (query === "") {
            const firstVisibleTab = Array.from(tabs_laliga).find(t => t.style.display !== "none");
            if(firstVisibleTab && !firstVisibleTab.classList.contains('active')){
                activateTab_laliga(firstVisibleTab);
            } else if (!firstVisibleTab && tabs_laliga.length > 0 && !tabs_laliga[0].classList.contains('active')) {
                activateTab_laliga(tabs_laliga[0]);
            }
        }
      });
    }
    const defaultActiveButtonLaliga = laligaContainer.querySelector('#verticalTabsMenu button.active');
    if (defaultActiveButtonLaliga) {
        // Default already active, no explicit call needed here unless iframe needs reload logic specific to internal tabs.
    } else if (tabs_laliga.length > 0) {
        // activateTab_laliga(tabs_laliga[0]); // Activate first tab if none are marked active
    }

}

    let previouslyActiveTabContent = null;

    function randomlySelectChannelForTab(tabRootElement) {
        if (!tabRootElement) {
            // console.log("Tab root element not provided for random selection.");
            return;
        }

        // Delay slightly to ensure any internal tab/channel setup has a chance to complete
        // and a default channel might have been loaded by the tab's own script.
        // Our random selection will then override this if applicable.
        setTimeout(() => {
            const activeChannelPanel = tabRootElement.querySelector('.channel-list .channel-panel.active');

            if (activeChannelPanel) {
                // Get all channel items within the active panel
                const channelItems = activeChannelPanel.querySelectorAll('.channel-item');

                // Filter for items that are currently visible (not hidden by search, for example)
                const visibleChannelItems = Array.from(channelItems).filter(item => {
                    const computedStyle = window.getComputedStyle(item);
                    return computedStyle.display !== 'none';
                });

                if (visibleChannelItems.length > 0) {
                    const randomIndex = Math.floor(Math.random() * visibleChannelItems.length);
                    const randomChannelToSelect = visibleChannelItems[randomIndex];

                    // console.log(`In tab ${tabRootElement.id}, randomly selecting channel: ${randomChannelToSelect.querySelector('.channel-name')?.textContent || 'Unknown Name'}`);

                    // Simulate a click on the channel item to trigger its existing selection logic
                    if (typeof randomChannelToSelect.click === 'function') {
                        randomChannelToSelect.click();
                    } else {
                        // console.warn("Randomly selected channel item does not have a click method.", randomChannelToSelect);
                    }
                } else {
                    // console.log(`No visible channels to select randomly in active panel of tab ${tabRootElement.id}.`);
                }
            } else {
                // console.log(`No active channel panel found in tab ${tabRootElement.id} for random selection.`);
            }
        }, 100); // 100ms delay. This can be adjusted if necessary.
    }


    function openTab(evt, tabName) {
        const currentTabContent = document.getElementById(tabName);
        if (!currentTabContent) {
            console.error("Target tab content not found:", tabName);
            return;
        }

        // 1. Unload iframes in the previously active tab (if it's different from the current)
        if (previouslyActiveTabContent && previouslyActiveTabContent !== currentTabContent) {
            const iframesToUnload = previouslyActiveTabContent.querySelectorAll("iframe");
            iframesToUnload.forEach(iframe => {
                const currentIframeSrc = iframe.src;
                if (currentIframeSrc && currentIframeSrc.toLowerCase() !== 'about:blank') {
                    if (!iframe.dataset.originalSrc || iframe.dataset.originalSrc.toLowerCase() !== 'about:blank') {
                         iframe.dataset.originalSrc = currentIframeSrc; 
                    }
                    iframe.src = 'about:blank'; 
                } else if (!iframe.dataset.originalSrc && iframe.dataset.src) { 
                     iframe.dataset.originalSrc = iframe.dataset.src;
                }
            });
        }

        // 2. Hide all tab contents and remove active class from tab links
        document.querySelectorAll(".tabcontent").forEach(tc => {
            if (tc !== currentTabContent) {
                tc.style.display = "none";
            }
        });
        document.querySelectorAll(".tablinks").forEach(tl => tl.classList.remove("active"));

        // 3. Show the current tab and set active class on its link
        currentTabContent.style.display = "block";
        if (evt && evt.currentTarget) { 
            evt.currentTarget.classList.add("active");
        }

        // 4. Randomly select a channel if the tab is a TV channel tab
        const targetTabId = currentTabContent.id;
        if (targetTabId === 'premier' || 
            targetTabId === 'premier2' ||
            targetTabId.startsWith('premier2_c')) { // Covers premier2_c1, premier2_c2, etc.

            randomlySelectChannelForTab(currentTabContent);
        }

        // 5. Load/Reload iframes in the current tab (main iframes like in 'laliga' or 'server1')
        // The iframes within premier*, premier2* are handled by their respective selectChannel functions.
        const iframesInCurrentTab = currentTabContent.querySelectorAll("iframe"); 
        iframesInCurrentTab.forEach(iframe => {
            // This logic primarily targets top-level iframes in tabs like 'laliga' or 'server1',
            // or iframes inside info-sections of 'premier' tabs that are not the main player.
            // The main player iframe (e.g. #streamFrame) in premier* tabs gets its src updated by selectChannel_...
            // So, we need to be careful not to overwrite what selectChannel just did if random selection occurred.

            // Only proceed if this iframe is NOT one of the main player iframes handled by selectChannel_...
            if (iframe.id && (iframe.id.startsWith('streamFrame') || iframe.id.startsWith('streamFrame_2'))) {
                 // This iframe's src is managed by selectChannel_... or changeStream_...
                 // If it's blank and has an originalSrc, it means it was unloaded.
                 // The random selection (if it happened) would have already set its src.
                 // If random selection didn't happen (e.g., no channels),
                 // and it was previously unloaded, we might want to restore its originalSrc.
                 // However, for premier* tabs, a channel should be selected (default or random).
                 // So, usually, we don't need to do much here for the main player iframe.
                 // If it's still 'about:blank' after random selection attempt, it means no channel loaded.
                 if (iframe.src.toLowerCase() === 'about:blank' && iframe.dataset.originalSrc && iframe.dataset.originalSrc.toLowerCase() !== 'about:blank') {
                    // This case is tricky. If random selection failed to pick a channel,
                    // and this iframe was previously active and then unloaded, should we restore it?
                    // For now, let the selectChannel logic be the sole source of truth for these player iframes.
                 }
                 return; // Skip further processing for main player iframes here
            }


            let intendedSrc = iframe.dataset.originalSrc; 

            if (!intendedSrc && iframe.dataset.src) { 
                intendedSrc = iframe.dataset.src;
                iframe.dataset.originalSrc = intendedSrc; 
                iframe.removeAttribute("data-src"); 
            }

            if (!intendedSrc && iframe.src && iframe.src.toLowerCase() !== 'about:blank') {
                intendedSrc = iframe.src;
                iframe.dataset.originalSrc = intendedSrc; 
            }

            if (intendedSrc && intendedSrc.toLowerCase() !== 'about:blank') {
                if (iframe.src.toLowerCase() === 'about:blank' || iframe.src !== intendedSrc) {
                    iframe.src = intendedSrc;
                }
            } else if (intendedSrc && intendedSrc.toLowerCase() === 'about:blank' && iframe.src.toLowerCase() !== 'about:blank') {
                iframe.src = 'about:blank';
            }
        });
        previouslyActiveTabContent = currentTabContent;
    }

    document.addEventListener("DOMContentLoaded", function() {
    const defaultOpenButton = document.getElementById("defaultOpen");
    if (defaultOpenButton) {
        const simulatedEvent = { currentTarget: defaultOpenButton };
        const tabNameToOpen = 'server2'; // এটি পরিবর্তন করে server2 করা হয়েছে
        openTab(simulatedEvent, tabNameToOpen);
    }
});
